{"code": "# Load NYSE stock symbols and create mapping
import json

def load_nyse_stocks():
    stockinfo_file = locals()['var_functions.query_db:16']
    with open(stockinfo_file, 'r') as f:
        stocks = json.load(f)
    return {stock['Symbol']: stock['Company Description'] for stock in stocks}

symbol_to_name = load_nyse_stocks()
symbols = list(symbol_to_name.keys())

print('__RESULT__:')
print(json.dumps({
    'total_symbols': len(symbols),
    'first_30_symbols': symbols[:30]
}))"}

